import { useState } from 'react';
import { sendContactForm } from '../utils/web3forms';

const ContactForm = () => {
  const [form, setForm] = useState({ name:'', email:'', message:'' });
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) =>
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      await sendContactForm(form);

      setSubmitted(true);
      setForm({ name:'', email:'', message:'' });

      setTimeout(() => {
        setSubmitted(false);
      }, 4000);

    } catch (err) {
      console.error(err);
      setError("Failed to send message. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = { width:'100%', padding:'12px 16px', border:'1px solid #e5e7eb', borderRadius:8, fontFamily:'DM Sans,sans-serif', fontSize:'0.92rem', color:'#1a1a2e', background:'#f9fafb', outline:'none', transition:'border-color 0.2s,box-shadow 0.2s', boxSizing:'border-box' };
  const labelStyle = { display:'block', fontFamily:'Syne,sans-serif', fontWeight:600, fontSize:'0.8rem', letterSpacing:'0.5px', color:'#3f444a', textTransform:'uppercase', marginBottom:'0.4rem' };

  const focusIn = (e) => {
    e.target.style.borderColor='#ec4848';
    e.target.style.boxShadow='0 0 0 3px rgba(236,72,72,0.12)';
    e.target.style.background='#fff';
  };

  const focusOut = (e) => {
    e.target.style.borderColor='#e5e7eb';
    e.target.style.boxShadow='none';
    e.target.style.background='#f9fafb';
  };

  return (
    <section id="contact" style={{ padding:'80px 0', background:'#1a1a2e' }}>
      <div className="container">

        {/* TITLE */}
        <div style={{ textAlign:'center', marginBottom:'3rem' }}>
          <h2 style={{ color:'#fff' }}>Let's Talk Fashion AI</h2>
        </div>

        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(280px,1fr))', gap:'3rem', maxWidth:900, margin:'0 auto' }}>

          {/* FORM */}
          <div style={{ background:'#fff', borderRadius:16, padding:'2rem' }}>

            {submitted ? (
              <div style={{ textAlign:'center' }}>
                <h3>Message Sent!</h3>
                <p>We'll get back to you as soon as possible.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit}>

                {/* ERROR */}
                {error && (
                  <p style={{ color:'red', marginBottom:'1rem' }}>
                    {error}
                  </p>
                )}

                <div style={{ marginBottom:'1rem' }}>
                  <label style={labelStyle}>Name</label>
                  <input
                    name="name"
                    value={form.name}
                    onChange={handleChange}
                    required
                    style={inputStyle}
                    onFocus={focusIn}
                    onBlur={focusOut}
                  />
                </div>

                <div style={{ marginBottom:'1rem' }}>
                  <label style={labelStyle}>Email</label>
                  <input
                    name="email"
                    type="email"
                    value={form.email}
                    onChange={handleChange}
                    required
                    style={inputStyle}
                    onFocus={focusIn}
                    onBlur={focusOut}
                  />
                </div>

                <div style={{ marginBottom:'1rem' }}>
                  <label style={labelStyle}>Message</label>
                  <textarea
                    name="message"
                    value={form.message}
                    onChange={handleChange}
                    required
                    rows={5}
                    style={inputStyle}
                    onFocus={focusIn}
                    onBlur={focusOut}
                  />
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    width:'100%',
                    background: loading ? '#999' : '#ec4848',
                    color:'#fff',
                    padding:'13px',
                    borderRadius:8,
                    cursor: loading ? 'not-allowed' : 'pointer'
                  }}
                >
                  {loading ? "Sending..." : "Send Message"}
                </button>

              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactForm;
